+        let permit = tx.reserve(&cx).expect("reserve failed");
+        let count = permit.send(42);
+        crate::assert_with_log!(count == 1, "receiver count", 1usize, count);
+
+        let got = block_on(rx.recv(&cx)).unwrap();
